import{_ as t,o as e,c as p,a2 as s}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"3.5 宗师装备制作的建议","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 之所以要把心理准备放到第一个来讲，是因为宗师的制作和喂养周期实在太长了， 不肝不氪不是老玩家有老底的话，做宗师简直遥遥无期（即使只需要70%经验）。 在你家族有不小的空地的情况下，猛肝一个","frontmatter":{"title":"3.5 宗师装备制作的建议","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 之所以要把心理准备放到第一个来讲，是因为宗师的制作和喂养周期实在太长了， 不肝不氪不是老玩家有老底的话，做宗师简直遥遥无期（即使只需要70%经验）。 在你家族有不小的空地的情况下，猛肝一个","outline":"deep"},"headers":[],"relativePath":"grandmaster/3-5.md","filePath":"grandmaster/3-5.md","lastUpdated":1782387794000}'),i={name:"grandmaster/3-5.md"};function u(l,a,r,g,o,d){return e(),p("div",null,[...a[0]||(a[0]=[s('<h1 id="_3-5-宗师装备制作的建议" tabindex="-1">3.5 宗师装备制作的建议 <a id="s246-d8877043"></a> <a class="header-anchor" href="#_3-5-宗师装备制作的建议" aria-label="Permalink to &quot;3.5 宗师装备制作的建议 &lt;a id=&quot;s246-d8877043&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_3-5-1-心理准备" tabindex="-1">3.5.1 心理准备 <a id="s247-05b0e707"></a> <a class="header-anchor" href="#_3-5-1-心理准备" aria-label="Permalink to &quot;3.5.1 心理准备 &lt;a id=&quot;s247-05b0e707&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>之所以要把心理准备放到第一个来讲，是因为宗师的制作和喂养周期实在太长了，</p><p>不肝不氪不是老玩家有老底的话，做宗师简直遥遥无期（即使只需要70%经验）。</p><p>在你家族有不小的空地的情况下，猛肝一个月左右能做出一身防具的白板。</p><p>每天肝的话30~45 天可以将一件宗师防具喂到太初（和平时间，内战可能得更久）</p><p>如果你还要做武器的话，你还需要准备圣物杖和神赐杖，这又是一笔不小的开支。</p><p>宗师里只有饰品是简单的，1 个月3 个觉醒圣物绰绰有余，但是接下来的版本饰品也可以解放了，虽然加成不算特别高，但是也要神赐才可以，因此不建议喂出圣物</p><p>0%经验的饰品。解放的神赐宗师饰品属性和现在苏醒太初属性是一样的。</p><p>其实吧，刨除运气因素，种宗师还是比买要贵不少的，宗师就和买房一样，全款最便宜，拉长时间还房贷其实是贵的，但是如果你要享受种的过程，跳经验的乐趣，</p><p>那就又不一样了。买杖其实也一样，有钱大量买低价杖其实比种狗粮还省，问题是：</p><p>你有金吗？</p><h2 id="_3-5-2-物质准备" tabindex="-1">3.5.2 物质准备 <a id="s248-c76f8737"></a> <a class="header-anchor" href="#_3-5-2-物质准备" aria-label="Permalink to &quot;3.5.2 物质准备 &lt;a id=&quot;s248-c76f8737&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>大量的空地——种地（看看做的材料表和喂的材料表你就明白了）</p><p>大量的跑商材料——跑金币</p><p>大量的领地币——制作宗师经验石头</p><h2 id="_3-5-3-金币准备" tabindex="-1">3.5.3 金币准备 <a id="s249-9df05192"></a> <a class="header-anchor" href="#_3-5-3-金币准备" aria-label="Permalink to &quot;3.5.3 金币准备 &lt;a id=&quot;s249-9df05192&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>做喂宗师没有金币是万万不行的，没金币怎么跑黑炭龙骨、怎么买霞光树、怎么买别人的领地币。而且就算你打算自己种，种子也得好几万金买呢。特化也得不少金呢。</p><p>以下笔者为你提供两种方案并为您计算了成本，你可以按需调整。</p><h3 id="偏肝方案" tabindex="-1">偏肝方案 <a id="s250-ff1b0e7b"></a> <a class="header-anchor" href="#偏肝方案" aria-label="Permalink to &quot;偏肝方案 &lt;a id=&quot;s250-ff1b0e7b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>按一身防具四叶草玫瑰花各120 组，羊毛150 组，对应黑炭18 组，这部分成本，</p><p>种子+羊棚成本6W 金左右，200J 挂一次委托，搓50 组布料成本10W 金，挂细须委托成本36036 金。18 组黑炭按地灵货算，41 一个货要4390 包货，按一船21 个算，</p><p>需要210 船，一个货按买货26 金算，交易品成本要114146 金。</p><p>以上还是基础的花销，算上后续林林总总的，挂委托至少准备近20W 金，买交易品跑黑炭龙骨要准备至少20W 金，种地薅羊毛准备至少6W 金。</p><p>菱石不考虑打本，火木靠买霞光树（你的领地币搓狗粮还要大几百个呢），按一颗霞光树300 金出15 个火木算，要224 颗霞光树，需花67200 金买。强化菱石变动大这里就不统计了但几万金还是需要的。</p><p>亚纳碎石按定格4J 扫拍卖要60480 金，庭院粉末算3 金一个要84000 金。</p><p>按6000 一组珊瑚草药准备66000 金。</p><p>也就说在你自己疯狂种地+疯狂跑商+扫一部分材料+挂委托+有跳经验的情况下，</p><p>一身太初防具，光经验部分成本就要73W 金。</p><p>然后还有觉醒，解放和精练，这里怎么也得花100W 金。</p><p>但是这套拉长时间战线的方案，可能需要你肝1-2 年！注意是肝，不是玩！</p><p>偏肝方案需要差不多200W 本金一身精练防具。</p><h3 id="偏买方案" tabindex="-1">偏买方案 <a id="s251-51bebf61"></a> <a class="header-anchor" href="#偏买方案" aria-label="Permalink to &quot;偏买方案 &lt;a id=&quot;s251-51bebf61&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>纯买黑炭龙骨可以大幅度减少时间，但是需要100W 金起步的花销。</p><p>找人种四叶草玫瑰花各120 组，自己种剩下的东西，大约需要30-40W 金，大批量订购不会太便宜，能多少看你讲价能力了。</p><p>委托求快可以从200 变成挂250，这样子整体花销只多5W 变成25W，但是时间上也会快不少。</p><p>亚纳碎石和烈火原木以及庭院粉末纯买花销大约50W 金。</p><p>领地币纯买方案还算便宜，最多花5-6W 金。</p><p>偏买方案精练一身防具花销大概需要300-350W 金。</p><h2 id="_3-5-4-关于巨匠双手杖" tabindex="-1">3.5.4 关于巨匠双手杖 <a id="s252-3d71baa8"></a> <a class="header-anchor" href="#_3-5-4-关于巨匠双手杖" aria-label="Permalink to &quot;3.5.4 关于巨匠双手杖 &lt;a id=&quot;s252-3d71baa8&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>圣物杖和神赐杖，只要你要喂武器就避不开这两东西，不过好在多数情况下，神赐杖价格其实和同经验神赐狗粮的价格差不多。</p><p>喂饰品不需要巨匠杖做狗粮。</p><p>远古杖8500 一根的话1 经验成本1.16 金，8000 一根的话1 经验成本1.1 金，</p><p>7500 的话1 经验成本1.02 金。</p><p>不朽杖16000 一根的话，1 经验成本2.06 金，14000 的话1 经验成本1.8 金。</p><p>圣物杖5W 一根的话，1 经验成本为6 金，5.8W 一根的话1 经验成本为7 金，</p><p>6W 一根的话1 经验成本为7.3 金。</p><p>神赐杖8W 一根的话，1 经验成本为9.3 金，9W 一根的话1 经验成本为10.5 金。</p><p>巨匠双手杖经验如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2578.jpeg" alt="图示：3.5.4 关于巨匠双手杖" loading="lazy"></figure><h2 id="_3-5-5-宗师装备的觉醒、解放与精练" tabindex="-1">3.5.5 宗师装备的觉醒、解放与精练 <a id="s253-30c17c42"></a> <a class="header-anchor" href="#_3-5-5-宗师装备的觉醒、解放与精练" aria-label="Permalink to &quot;3.5.5 宗师装备的觉醒、解放与精练 &lt;a id=&quot;s253-30c17c42&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>觉醒卷轴和解放卷轴制作材料如下：</p><p>注意：觉醒不是100%成功，因此建议多备点材料。</p><p>精练卷轴如下：</p><p>第一个和第二个材料都是大草原刷怪掉落，刷怪掉碎片，50 个碎片合成一个大的。</p><p>毕业火枪一小时爆率如下：</p><p>这个算是运气比较好的，平均一小时只有60-80 个，还得4S 左右一个怪才能打出这个成绩（必须有拾取），也就是说一般你自己刷，大约要7-8 小时才能觉醒一次</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2585.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2586.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2592.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2593.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2598.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2599.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2604.jpeg" alt="图示：3.5.5 宗师装备的觉醒、解放与精练" loading="lazy"></figure><h2 id="_3-5-6-宗师石头的制作" tabindex="-1">3.5.6 宗师石头的制作 <a id="s254-dead43ff"></a> <a class="header-anchor" href="#_3-5-6-宗师石头的制作" aria-label="Permalink to &quot;3.5.6 宗师石头的制作 &lt;a id=&quot;s254-dead43ff&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>按下O 键，点击搜索栏，搜伊弗尼尔月影，就可以搜到宗师石头的制作材料。</p><p>我们以烈焰石头为例：</p><p>不同宗师石头需要的4 级油不同，具体可以自行在游戏里查看。</p><p>不同月影的套装效果也不一样，具体可以在游戏内自行查看，全部月影都有8 件套双手增强效果。因此建议宗师都搞个弓打石头。</p><p>注意：宗师乐器不能打宗师石头！！！</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2609.jpeg" alt="图示：3.5.6 宗师石头的制作" loading="lazy"></figure>',72)])])}const h=t(i,[["render",u]]);export{c as __pageData,h as default};
